import { promises as fs } from "node:fs";
import path from "node:path";
import { listArticles, readArticle, PROJECT_ROOT } from "../lib/content-store.mjs";

const OUTPUT_PATH = path.join(PROJECT_ROOT, "database", "d1-seed.sql");

const articles = await listArticles();
const statements = [
  "-- Generated by scripts/export-posts-to-d1-seed.mjs",
  "-- Re-run this file whenever content/posts/*.md changes and you want to seed D1.",
  "BEGIN TRANSACTION;",
];

for (const item of articles) {
  const article = await readArticle(item.slug);
  const metadata = article.metadata;
  const now = metadata.updated_at || new Date().toISOString();
  const row = {
    schema_version: metadata.schema_version || 1,
    title: metadata.title || item.title || "Untitled",
    slug: metadata.slug || item.slug,
    status: metadata.status || "draft",
    article_type: metadata.article_type || "review",
    source_type: metadata.source_type || "manual",
    published_at: metadata.published_at || "",
    updated_at: now,
    excerpt: metadata.excerpt || "",
    seo_title: metadata.seo_title || "",
    product_title: metadata.product_title || metadata.title || "",
    circle_name: metadata.circle_name || "",
    author_name: metadata.author_name || "",
    source_url: metadata.source_url || "",
    affiliate_url: metadata.affiliate_url || "",
    thumbnail_url: metadata.thumbnail_url || "",
    genres_json: JSON.stringify(metadata.genres || []),
    emotions_json: JSON.stringify(metadata.emotions || []),
    rights_status: metadata.rights_status || "pending_review",
    pr_label: metadata.pr_label || "PR",
    automation_ready: metadata.automation_ready ? 1 : 0,
    body: article.body || "",
    product_id: extractProductId(metadata.source_url) || extractProductId(metadata.thumbnail_url) || null,
    created_at: metadata.published_at || now,
    imported_at: null,
  };

  const columns = Object.keys(row);
  statements.push(
    `INSERT INTO articles (${columns.join(", ")}) VALUES (${columns
      .map((column) => sqlValue(row[column]))
      .join(", ")}) ON CONFLICT(slug) DO UPDATE SET ${columns
      .filter((column) => column !== "slug" && column !== "created_at")
      .map((column) => `${column}=excluded.${column}`)
      .join(", ")};`
  );
}

statements.push("COMMIT;", "");
await fs.mkdir(path.dirname(OUTPUT_PATH), { recursive: true });
await fs.writeFile(OUTPUT_PATH, statements.join("\n"), "utf8");
console.log(`Wrote ${path.relative(PROJECT_ROOT, OUTPUT_PATH)} (${articles.length} articles).`);

function sqlValue(value) {
  if (value === null || value === undefined) return "NULL";
  if (typeof value === "number") return String(value);
  return `'${String(value).replace(/'/gu, "''")}'`;
}

function extractProductId(value) {
  const decoded = String(value || "");
  const patterns = [
    /[?&]cid=([^/?&#]+)/iu,
    /\/digital\/comic\/([^/?&#]+)/iu,
    /\/(d_\d+)(?:[/?#._-]|$)/iu,
    /\b(d_\d+)(?=pr\.|pl\.)/iu,
  ];

  for (const pattern of patterns) {
    const match = decoded.match(pattern);
    if (match?.[1]) return match[1];
  }

  return "";
}
